import { Config } from "../../Configs.js";
import { getEntityData, getUserInfo, getFile, getFilterEntityData, getFilterEntityCount } from "../../endpoints.js";
import { CloseDialog, renderRightSidebar, drawTagsIntoTables, filterDataByHeaderType, inputObserver, pageNumbers, fillBtnPagination, calculateLine, searchUniversalSingle } from "../../tools.js";
import { UIContentLayout } from "./Layout.js";
import { UITableSkeletonTemplate } from "./Template.js";
// Local configs
const tableRows = 100;//Config.tableRows;
let currentPage = Config.currentPage;
const pageName = 'Alertas / Rutinas no cumplidas';
const customerId = localStorage.getItem('customer_id');
let infoPage = {
    count1: 0,//RoutineRegister
    count2: 0,//Notification
    data1: [],//RoutineRegister
    data2: [],//Notification
    counter: 10,
    table: ["RoutineRegister", "Notification"],
    newRegister: false,
    countNewRegister1: 0,
    countNewRegister2: 0,
};
let dataPage;
let raw1; //RoutineRegister
let raw2; //Notification
const GetAlerts = async () => {
    //const notesRaw = await getEntitiesData('RoutineRegister');
    //const notes = notesRaw.filter((data) => data.customer?.id === `${customerId}`);
    infoPage.counter = 10;
    clearTimeout(Config.timeOut);
    raw1 = JSON.stringify({
        "filter": {
            "conditions": [
                {
                    "property": "business.id",
                    "operator": "=",
                    "value": `${Config.currentUser.business.id}`
                },
                {
                    "property": "routineState.name",
                    "operator": `=`,
                    "value": `No cumplido`
                }
            ]
        },
        sort: "-createdDate",
        limit: Config.tableRows,
        //offset: infoPage.offset,
        fetchPlan: 'full',
    });

    raw2 = JSON.stringify({
        "filter": {
            "conditions": [
                {
                    "property": "business.id",
                    "operator": "=",
                    "value": `${Config.currentUser.business.id}`
                },
                {
                    "property": "notificationType.name",
                    "operator": "<>",
                    "value": `Visita`
                },
                {
                    "property": "notificationType.name",
                    "operator": "<>",
                    "value": `Vehicular`
                },
                {
                    "property": "notificationType.name",
                    "operator": "<>",
                    "value": `Nota`
                },
                {
                    "property": "notificationType.name",
                    "operator": "<>",
                    "value": `Consigna`
                },
                {
                    "property": "notificationType.name",
                    "operator": "<>",
                    "value": `Rutina`
                }
            ]
        },
        sort: "-createdDate",
        limit: Config.tableRows,
        //offset: infoPage.offset,
        fetchPlan: 'full',
    });

    for(let i = 0; i < infoPage.table.length; i++){
        if(infoPage.table[i] == "RoutineRegister"){
            if(infoPage.count1 == 0 || infoPage.countNewRegister1 > 0){
                infoPage.count1 = await getFilterEntityCount("RoutineRegister", raw1);
                infoPage.data1 = await getFilterEntityData("RoutineRegister", raw1);
            }
        }else if(infoPage.table[i] == "Notification"){
            if(infoPage.count2 == 0 || infoPage.countNewRegister2 > 0){
                infoPage.count2 = await getFilterEntityCount("Notification", raw2);
                infoPage.data2 = await getFilterEntityData("Notification", raw2);
            }
        }
    }
    dataPage = [...infoPage.data1, ...infoPage.data2];
    dataPage.sort((a,b) => {
        let dateA = new Date(`${a.createdDate}`);
        let dateB = new Date(`${b.createdDate}`);
        return dateB - dateA;
    });
    return dataPage;
};
export class AlertsRegisters {
    constructor() {
        this.dialogContainer = document.getElementById('app-dialogs');
        this.siebarDialogContainer = document.getElementById('entity-editor-container');
        this.appContainer = document.getElementById('datatable-container');
        this.render = async (data1, data2, count1, count2, countNewRegister1, countNewRegister2) => {
            Config.currentScreen = "AlertsRegisters";
            infoPage.data1 = data1;
            infoPage.data2 = data2;
            infoPage.count1 = count1;
            infoPage.count2 = count2;
            infoPage.countNewRegister1 = countNewRegister1;
            infoPage.countNewRegister2 = countNewRegister2;
            this.appContainer.innerHTML = '';
            this.appContainer.innerHTML = UIContentLayout;
            // Getting interface elements
            const viewTitle = document.getElementById('view-title');
            const tableBody = document.getElementById('datatable-body');
            // Changing interface element content
            viewTitle.innerText = pageName;
            tableBody.innerHTML = '.Cargando... Esto puede tomar unos momentos';
            let notesArray = await GetAlerts();
            //console.log(notesArray)
            //if(infoPage.currentPage == 1){
                const change = async () => {
                    clearTimeout(Config.timeOut);
                    if(infoPage.counter == Config.timeReolad){
                        const newRegisters1 = await getFilterEntityCount(infoPage.table[0], raw1);
                        const newRegisters2 = await getFilterEntityCount(infoPage.table[1], raw2);
                        //console.log(infoPage.count);
                        //console.log(newRegisters);
                        if(newRegisters1 > infoPage.count1 || newRegisters2 > infoPage.count2){
                            console.log("updates detected")
                            infoPage.newRegister = true;
                            infoPage.countNewRegister1 = newRegisters1 - infoPage.count1;
                            infoPage.countNewRegister2 = newRegisters2 - infoPage.count2;
                            new AlertsRegisters().render(infoPage.data1, infoPage.data2, infoPage.count1, infoPage.count2, infoPage.countNewRegister1, infoPage.countNewRegister2);
                        }else{
                            console.log("no updates")
                            Config.timeOut = setTimeout(change, infoPage.counter);
                        }
                        
                    }else if(infoPage.counter == 10){
                        infoPage.counter = Config.timeReolad;
                        Config.timeOut = setTimeout(change, infoPage.counter);
                    }
                }
                Config.timeOut = setTimeout(change, infoPage.counter);
            //}else{
            //    clearTimeout(Config.timeOut);
            //}
            tableBody.innerHTML = UITableSkeletonTemplate.repeat(tableRows);
            // Exec functions
            this.load(tableBody, currentPage, notesArray);
            // Rendering icons
        };
        this.load = async (tableBody, currentPage, notes) => {
            tableBody.innerHTML = ''; // clean table
            // configuring max table row size
            currentPage--;
            let start = tableRows * currentPage;
            let end = start + tableRows;
            let paginatedItems = notes.slice(start, end);
            // Show message if page is empty
            if (notes.length === 0) {
                let mensaje = 'No existen datos';
                if(customerId == null){mensaje = 'Seleccione una empresa';}
                let row = document.createElement('TR');
                row.innerHTML = `
            <td>${mensaje}<td>
            <td></td>
            <td></td>
            `;
                tableBody.appendChild(row);
            }
            else {
                for (let i = 0; i < paginatedItems.length; i++) {
                    let register = paginatedItems[i]; // getting note items
                    //let obsMessage = await this.obtainDelay(register);
                    let row = document.createElement('TR');
                    if(register._entityName == "RoutineRegister"){

                        row.innerHTML += `
                            <td>${calculateLine(register?.customer?.name, 40)}</td>
                            <td>Rutina no cumplida</td>
                            <td>${calculateLine(register?.routine?.name, 40)} | ${calculateLine(register?.routineSchedule?.name, 40)}</td>
                            <td>${calculateLine(`${register?.user?.firstName ?? ''} ${register?.user?.lastName ?? ''}`, 40)}</td>
                            <td id="table-date">${register?.creationDate ?? ''} ${register?.creationTime ?? ''}</td>
                            <td id="td-alert-${register.id}"></td>
                        `;
                        tableBody.appendChild(row);
                        //this.previewNote(note.id);
                        
                        // TODO: Corret this fixer
                        // fixDate()
                        if(i+1 <= infoPage.countNewRegister1){
                            if(register?.routineState?.name == 'No cumplido'){
                                let divNewRegister = document.getElementById(`td-alert-${register.id}`);
                                divNewRegister.innerHTML = `
                                    <button class="button" id="entity-alert" data-entityId="${register.id}">
                                        <i class="fa-solid fa-circle-exclamation" id="btnAlarm-${register.id}"></i>
                                    </button>
                                `;
                                let color = 1;
                                //const audio = new Audio("./public/src/assets/sounds/alarm.mp3");
                                let timeTemp = 1000;
                                let btnAlarm = document.getElementById(`btnAlarm-${register.id}`);
                                let alarmIcon = async () => {
                                    //audio.pause();
                                    if(color == 1){
                                        btnAlarm.style.color = "red";
                                        color = 2;
                                    }else{
                                        btnAlarm.style.color = "orange";
                                        color = 1;
                                    }
                                    setTimeout(alarmIcon, timeTemp);
                                }
                                setTimeout(alarmIcon, timeTemp);
                                //audio.play();
                                infoPage.newRegister = false;
                            }else{
                                infoPage.newRegister = false;
                            }

                        }
                    }else if(register._entityName == "Notification"){

                        row.innerHTML += `
                            <td>${calculateLine(register?.customer?.name, 40)}</td>
                            <td>Alerta</td>
                            <td>${calculateLine(register?.description ?? '', 40)}</td>
                            <td>${calculateLine(`${register?.user?.firstName ?? ''} ${register?.user?.lastName ?? ''}`, 40)}</td>
                            <td id="table-date">${register?.creationDate ?? ''} ${register?.creationTime ?? ''}</td>
                            <td id="td-alert-${register.id}"></td>
                        `;
                        tableBody.appendChild(row);
                        //this.previewNote(note.id);
                        if(i+1 <= infoPage.countNewRegister2){

                            let divNewRegister = document.getElementById(`td-alert-${register.id}`);
                            divNewRegister.innerHTML = `
                                <button class="button" id="entity-alert" data-entityId="${register.id}">
                                    <i class="fa-solid fa-circle-exclamation" id="btnAlarm-${register.id}"></i>
                                </button>
                            `;
                            let color = 1;
                            //const audio = new Audio("./public/src/assets/sounds/alarm.mp3");
                            let timeTemp = 1000;
                            let btnAlarm = document.getElementById(`btnAlarm-${register.id}`);
                            let alarmIcon = async () => {
                                //audio.pause();
                                if(color == 1){
                                    btnAlarm.style.color = "red";
                                    color = 2;
                                }else{
                                    btnAlarm.style.color = "orange";
                                    color = 1;
                                }
                                setTimeout(alarmIcon, timeTemp);
                            }
                            setTimeout(alarmIcon, timeTemp);
                            //audio.play();
                            infoPage.newRegister = false;

                        }
                    }
                }
            }
        };
    }
}
